const leadId = $('Upsert Conversa').item.json.lead_id;
const leadInfo = $('Atualizar Lead').item?.json || $('Criar Lead').item?.json || {};
const mensagens = $input.all();

// Montar histórico da conversa
const historico = mensagens
  .filter(m => m.json.conteudo)
  .reverse()
  .map(m => `[${m.json.direcao === 'inbound' ? 'Cliente' : 'Agente'}]: ${m.json.conteudo}`)
  .join('\n');

const prompt = `Você é um analista de crédito especialista. Analise a conversa abaixo e retorne APENAS um JSON válido, sem markdown, sem explicações.

LEAD ATUAL:
- ID: ${leadId}
- Nome: ${leadInfo.nome || 'Desconhecido'}
- Status atual: ${leadInfo.status || 'novo'}
- Etapa atual: ${leadInfo.etapa_funil || 'Novo'}
- Score atual: ${leadInfo.score_ia || 0}

HISTÓRICO DA CONVERSA (mais recente por último):
${historico || 'Sem histórico disponível'}

Retorne EXATAMENTE este JSON (sem markdown):
{
  "score": <número 0-100>,
  "temperatura": <"frio"|"morno"|"quente"|"urgente">,
  "etapa_sugerida": <"Novo"|"Contato Feito"|"Qualificado"|"Proposta Enviada"|"Negociação"|"Documentação"|"Aprovação"|"Ganho"|"Perdido">,
  "resumo": <"resumo em 1-2 frases do perfil do lead">,
  "proxima_acao": <"próxima ação recomendada">,
  "probabilidade_conversao": <número 0-100>,
  "documentos_faltando": [<lista de documentos pendentes ou array vazio>],
  "pontos_positivos": [<lista de pontos positivos ou array vazio>],
  "pontos_atencao": [<lista de pontos de atenção ou array vazio>],
  "nome_identificado": <"nome real identificado na conversa ou null">,
  "empresa_identificada": <"nome da empresa ou null">,
  "produto_interesse": <"produto de interesse ou null">,
  "valor_estimado": <"valor estimado ou null">
}`;

return [{ json: { prompt, leadId, leadInfo } }];

const rawText = $input.first().json.text || $input.first().json.content || '';

// Remover markdown code blocks se presentes
const cleaned = rawText
  .replace(/```json\n?/gi, '')
  .replace(/```\n?/gi, '')
  .trim();

let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch (e) {
  // Tentar extrair JSON do texto
  const match = cleaned.match(/\{[\s\S]*\}/);
  if (match) {
    try {
      parsed = JSON.parse(match[0]);
    } catch (e2) {
      parsed = {
        score: 0,
        temperatura: 'frio',
        etapa_sugerida: 'Novo',
        resumo: 'Erro ao parsear resposta da IA',
        proxima_acao: 'Revisar manualmente',
        probabilidade_conversao: 0,
        documentos_faltando: [],
        pontos_positivos: [],
        pontos_atencao: ['Erro no processamento da IA'],
        nome_identificado: null,
        empresa_identificada: null,
        produto_interesse: null,
        valor_estimado: null
      };
    }
  }
}

return [{ json: { ...parsed, leadId: $('Montar Prompt').item.json.leadId } }];

